import{_ as a,a as t,b as o,c as n}from"./chunks/授权完复制token.D-mju0qq.js";import{_ as l,o as i,c as s,a2 as r}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Een Google Drive-kanaal toevoegen","description":"","frontmatter":{},"headers":[],"relativePath":"nl-NL/upload/google-drive.md","filePath":"nl-NL/upload/google-drive.md","lastUpdated":1781962217000}'),d={name:"nl-NL/upload/google-drive.md"};function p(c,e,h,g,u,k){return i(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="een-google-drive-kanaal-toevoegen" tabindex="-1">Een Google Drive-kanaal toevoegen <a class="header-anchor" href="#een-google-drive-kanaal-toevoegen" aria-label="Permalink to &quot;Een Google Drive-kanaal toevoegen&quot;">​</a></h1><h2 id="wat-je-vooraf-nodig-hebt" tabindex="-1">Wat je vooraf nodig hebt <a class="header-anchor" href="#wat-je-vooraf-nodig-hebt" aria-label="Permalink to &quot;Wat je vooraf nodig hebt&quot;">​</a></h2><p>Bereid deze zaken voor:</p><table tabindex="0"><thead><tr><th>Vereiste</th><th>Waarom je dit nodig hebt</th></tr></thead><tbody><tr><td>Google-account</td><td>Voor toegang tot Google Cloud en autorisatie van Google Drive</td></tr><tr><td>Google Cloud-project</td><td>Voor het inschakelen van de Drive API en het maken van OAuth-gegevens</td></tr><tr><td>OAuth 2.0-client</td><td>Hiermee kan ImgBed <code>Client ID</code>, <code>Client Secret</code> en <code>Refresh Token</code> ophalen</td></tr><tr><td>Je ImgBed-domein</td><td>Voor de OAuth-redirect-URI. Dit moet overeenkomen met het domein dat je echt gebruikt.</td></tr></tbody></table><h2 id="instellen" tabindex="-1">Instellen <a class="header-anchor" href="#instellen" aria-label="Permalink to &quot;Instellen&quot;">​</a></h2><h3 id="stap-1-schakel-de-google-drive-api-in" tabindex="-1">Stap 1: Schakel de Google Drive API in <a class="header-anchor" href="#stap-1-schakel-de-google-drive-api-in" aria-label="Permalink to &quot;Stap 1: Schakel de Google Drive API in&quot;">​</a></h3><ol><li>Open Google Cloud Console.</li><li>Maak een nieuw project of selecteer een bestaand project.</li><li>Ga naar <code>APIs &amp; Services</code>.</li><li>Klik op <code>Enable APIs and Services</code>.</li><li>Zoek naar <code>Google Drive API</code>.</li><li>Open deze en klik op inschakelen.</li></ol><h3 id="stap-2-configureer-het-oauth-toestemmingsscherm" tabindex="-1">Stap 2: Configureer het OAuth-toestemmingsscherm <a class="header-anchor" href="#stap-2-configureer-het-oauth-toestemmingsscherm" aria-label="Permalink to &quot;Stap 2: Configureer het OAuth-toestemmingsscherm&quot;">​</a></h3><ol><li>Open in Google Cloud <code>Google Auth Platform</code>.</li><li>Vul de basisinformatie in bij <code>Branding</code>, zoals appnaam, supportmail en ontwikkelaarcontact.</li><li>Open <code>Audience</code>.</li><li>Voor de meeste persoonlijke self-hosted installaties kies je <code>External</code>.</li><li>Kies je <code>External</code>, voeg dan bij <code>Test users</code> het Google-account toe dat je wilt autoriseren.</li><li>Open <code>Data Access</code>.</li><li>Voeg de benodigde Google Drive-rechten toe.</li></ol><h3 id="stap-3-maak-een-oauth-2-0-client" tabindex="-1">Stap 3: Maak een OAuth 2.0-client <a class="header-anchor" href="#stap-3-maak-een-oauth-2-0-client" aria-label="Permalink to &quot;Stap 3: Maak een OAuth 2.0-client&quot;">​</a></h3><ol><li>Open in <code>Google Auth Platform</code> de sectie <code>Clients</code>.</li><li>Maak een nieuwe client.</li><li>Zet het toepassingstype op <code>Web application</code>.</li><li>Geef de client een herkenbare naam.</li><li>Vul bij authorized JavaScript origins je ImgBed-URL in, bijvoorbeeld:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com</span></span></code></pre></div><ol start="6"><li>Vul bij authorized redirect URIs in:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com/api/oauth/google/callback</span></span></code></pre></div><p><img src="'+a+'" alt="OAuth-client maken" loading="lazy"></p><p><img src="'+t+'" alt="Domein en callback-URL invullen" loading="lazy"></p><p>Kopieer na het aanmaken deze waarden:</p><table tabindex="0"><thead><tr><th>Gegenereerde waarde</th><th>ImgBed-veld</th></tr></thead><tbody><tr><td>Client ID</td><td><code>Client ID</code></td></tr><tr><td>Client Secret</td><td><code>Client Secret</code></td></tr></tbody></table><h2 id="stap-4-vul-het-google-drive-kanaal-in" tabindex="-1">Stap 4: Vul het Google Drive-kanaal in <a class="header-anchor" href="#stap-4-vul-het-google-drive-kanaal-in" aria-label="Permalink to &quot;Stap 4: Vul het Google Drive-kanaal in&quot;">​</a></h2><p>Kies in Uploadinstellingen <code>Google Drive</code> en vul in:</p><table tabindex="0"><thead><tr><th>ImgBed-veld</th><th>Wat je invult</th></tr></thead><tbody><tr><td>Kanaalnaam</td><td>Een herkenbare naam, bijvoorbeeld <code>Main Google Drive</code></td></tr><tr><td>Client ID</td><td>De Client ID uit Google Cloud</td></tr><tr><td>Client Secret</td><td>Het Client Secret uit Google Cloud</td></tr><tr><td>Refresh Token</td><td>Laat voorlopig leeg. Dit haal je in de volgende stap op.</td></tr><tr><td>Hoofdmap</td><td>Optioneel. Standaard <code>imgbed</code>.</td></tr></tbody></table><p><img src="'+o+'" alt="Clientgegevens in ImgBed invullen" loading="lazy"></p><h2 id="stap-5-haal-het-refresh-token-op" tabindex="-1">Stap 5: Haal het Refresh Token op <a class="header-anchor" href="#stap-5-haal-het-refresh-token-op" aria-label="Permalink to &quot;Stap 5: Haal het Refresh Token op&quot;">​</a></h2><ol><li>Klik op <code>Get Token</code>.</li><li>Kies het Google-account dat je wilt koppelen.</li><li>Rond de autorisatiestappen af.</li><li>De callbackpagina toont een <code>Refresh Token</code>.</li><li>Kopieer het.</li><li>Ga terug naar ImgBed en plak het in <code>Refresh Token</code>.</li></ol><p><img src="'+n+`" alt="Refresh Token na autorisatie kopiëren" loading="lazy"></p><p>Als je later van Google-account wisselt, de OAuth-client verandert of de oude autorisatie verloopt, hoef je het kanaal niet te verwijderen. Open de bewerkpagina en klik op <code>Reauthorize</code>.</p><h2 id="stap-6-sla-het-kanaal-op" tabindex="-1">Stap 6: Sla het kanaal op <a class="header-anchor" href="#stap-6-sla-het-kanaal-op" aria-label="Permalink to &quot;Stap 6: Sla het kanaal op&quot;">​</a></h2><p>Sla het kanaal op zodra alle velden zijn ingevuld.</p><h2 id="snelle-flow" tabindex="-1">Snelle flow <a class="header-anchor" href="#snelle-flow" aria-label="Permalink to &quot;Snelle flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Open Google Cloud</span></span>
<span class="line"><span>-&gt; Maak of selecteer een project</span></span>
<span class="line"><span>-&gt; Schakel Google Drive API in</span></span>
<span class="line"><span>-&gt; Configureer Google Auth Platform</span></span>
<span class="line"><span>-&gt; Voeg bij Audience = External je Google-account toe aan Test users</span></span>
<span class="line"><span>-&gt; Maak een OAuth-client van het type Web application</span></span>
<span class="line"><span>-&gt; Gebruik https://your-domain.com/api/oauth/google/callback als redirect URI</span></span>
<span class="line"><span>-&gt; Vul Client ID en Client Secret in ImgBed in</span></span>
<span class="line"><span>-&gt; Klik Get Token</span></span>
<span class="line"><span>-&gt; Log in met Google en autoriseer</span></span>
<span class="line"><span>-&gt; Kopieer het Refresh Token van de callbackpagina</span></span>
<span class="line"><span>-&gt; Plak het in ImgBed en sla op</span></span>
<span class="line"><span>-&gt; Upload een testafbeelding</span></span></code></pre></div><h2 id="referenties" tabindex="-1">Referenties <a class="header-anchor" href="#referenties" aria-label="Permalink to &quot;Referenties&quot;">​</a></h2><ol><li>Google OAuth Web Server Applications: <a href="https://developers.google.com/identity/protocols/oauth2/web-server" target="_blank" rel="noreferrer">https://developers.google.com/identity/protocols/oauth2/web-server</a></li><li>Google Workspace OAuth Consent Configuration: <a href="https://developers.google.com/workspace/guides/configure-oauth-consent" target="_blank" rel="noreferrer">https://developers.google.com/workspace/guides/configure-oauth-consent</a></li><li>Google Drive API Auth Scopes: <a href="https://developers.google.com/workspace/drive/api/guides/api-specific-auth" target="_blank" rel="noreferrer">https://developers.google.com/workspace/drive/api/guides/api-specific-auth</a></li></ol>`,32)])])}const f=l(d,[["render",p]]);export{b as __pageData,f as default};
